import React from 'react';
import { Helmet } from 'react-helmet-async';
import HookWatch from './HookWatch';

function App() {
  return (
    <>
      <Helmet>
        <title>HookWatch - Precision Online Stopwatch</title>
        <meta name="description" content="A full-featured online stopwatch with lap times, precision timing, and modern UI. Built with React hooks for accurate performance." />
        <meta name="keywords" content="stopwatch, timer, chronograph, lap times, precision timing, online stopwatch, react stopwatch" />
        <meta name="author" content="HookWatch Team" />

        {/* Open Graph / Facebook */}
        <meta property="og:type" content="website" />
        <meta property="og:url" content="https://hookwatch.example.com/" />
        <meta property="og:title" content="HookWatch - Precision Online Stopwatch" />
        <meta property="og:description" content="A full-featured online stopwatch with lap times, precision timing, and modern UI." />
        <meta property="og:image" content="https://hookwatch.example.com/og-image.png" />

        {/* Twitter */}
        <meta property="twitter:card" content="summary_large_image" />
        <meta property="twitter:url" content="https://hookwatch.example.com/" />
        <meta property="twitter:title" content="HookWatch - Precision Online Stopwatch" />
        <meta property="twitter:description" content="A full-featured online stopwatch with lap times, precision timing, and modern UI." />
        <meta property="twitter:image" content="https://hookwatch.example.com/og-image.png" />

        {/* Additional meta tags */}
        <meta name="robots" content="index, follow" />
        <meta name="language" content="English" />
        <meta name="viewport" content="width=device-width, initial-scale=1.0" />
        <meta http-equiv="Content-Type" content="text/html; charset=UTF-8" />

        {/* Favicon */}
        <link rel="icon" type="image/svg+xml" href="data:image/svg+xml,<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 100 100'><text y='.9em' font-size='90'>⏱️</text></svg>" />

        {/* Theme color */}
        <meta name="theme-color" content="#667eea" />

        {/* Apple touch icon */}
        <link rel="apple-touch-icon" href="data:image/svg+xml,<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 100 100'><text y='.9em' font-size='90'>⏱️</text></svg>" />
      </Helmet>

      <div className="App">
        <HookWatch />
      </div>
    </>
  );
}

export default App;
